// cli.ts
import { quote, claim, insuranceSum, type Item } from "./claim-office.js";

const KNOWN_ITEM_TYPES = new Set([
  "sword",
  "amulet",
  "staff",
  "potion",
  "rune",
  "moonstone",
]);

type QuoteStep = { op: "quote"; items: Item[] };
type ClaimStep = {
  op: "claim";
  policy: number;
  incident: { cause: string; damages: { itemType: string; amount: number }[] };
};
type Step = QuoteStep | ClaimStep;

type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: Step[];
};

async function readStdin(): Promise<string> {
  const chunks: Buffer[] = [];
  for await (const chunk of process.stdin) {
    chunks.push(chunk as Buffer);
  }
  return Buffer.concat(chunks).toString("utf8");
}

async function main() {
  const raw = await readStdin();
  const scenario: Scenario = JSON.parse(raw);

  const results: Array<
    { premium: number } | { payout: number; remainingCap: number }
  > = [];

  const policyCaps: number[] = [];
  const policyItems: Item[][] = [];
  let previousContracts = 0;

  for (const step of scenario.steps) {
    if (step.op === "quote") {
      for (const item of step.items) {
        if (!KNOWN_ITEM_TYPES.has(item.type)) {
          console.error(`Unknown item type: ${item.type}`);
          process.exit(1);
        }
      }
      const premium = quote({
        items: step.items,
        customerYears: scenario.customer.yearsWithMHPCO,
        previousContracts,
      });
      results.push({ premium });
      policyItems.push(step.items);
      policyCaps.push(insuranceSum(step.items) * 2);
      previousContracts += 1;
    } else if (step.op === "claim") {
      const idx = step.policy;
      const items = policyItems[idx];
      const remainingCap = policyCaps[idx];
      const result = claim({
        items,
        remainingCap,
        damages: step.incident.damages,
      });
      policyCaps[idx] = result.remainingCap;
      results.push(result);
    }
  }

  console.log(JSON.stringify({ results }));
}

main().catch((err) => {
  console.error(err instanceof Error ? err.message : String(err));
  process.exit(1);
});
